-- graph schema version: 1.0.0
--
-- Mirrors docs/toll-graph-spec.md. Keep in sync; the graph schema version
-- below must match the spec and is enforced by tests/test_graph.py.
--
-- Curated NOVA toll graph: i95_express + i495_express dynamic edges (317
-- OD pairs from the I-95/395/495 Express Lanes feed), i66_itb dynamic
-- edges (20 zone pairs from the I-66 ITB feed), and free junction
-- connector edges (feed IS NULL) at Springfield and the Beltway/66
-- interchange. Topology is static seed data; rebuild is the migration
-- strategy -- this file is idempotent (safe to re-run).

BEGIN;

DROP TABLE IF EXISTS graph_edge, graph_node;

CREATE TABLE graph_node (
    node_id  text PRIMARY KEY,   -- stable slug: 'i95x:garrisonville', 'i66:fairfax-dr'
    name     text NOT NULL,      -- canonical display name (hand-curated)
    corridor text NOT NULL CHECK (corridor IN ('i95_express','i495_express','i66_itb'))
);

CREATE TABLE graph_edge (
    from_node     text NOT NULL REFERENCES graph_node,
    to_node       text NOT NULL REFERENCES graph_node,
    feed          text CHECK (feed IN ('i95','i66')),   -- NULL = free junction connector
    od_pair_id    int,                                   -- i95 price key
    start_zone_id int, end_zone_id int                   -- i66 price key
);

-- Nodes (60): i95_express (34), i495_express (18), i66_itb (8).

-- Edges (341): i95/i495 dynamic (317, keyed od_pair_id), i66 dynamic
-- (20, keyed start_zone_id/end_zone_id), junction connectors (4, feed NULL).
-- Springfield express-to-express ramps. NB: i95x trips end at the bare "I-495"
-- node, then continue as the "I-395-95 HOV TO …" 495-NB family (starts TP1NB;
-- the "I-395-95-495" family is GP entry at TP2NB, not this movement). SB: 495
-- trips ending "TO I-95 HOV" (south) or "TO I-395-495 HOV" (north, reversible)
-- both continue as i95-corridor trips from the bare "I-495" origin.

COMMIT;
